const { conversation_id, agent_id, transcript } = $input.first().json;
const last_message = transcript?.at(-1)?.message ?? null;
const last_role = transcript?.at(-1)?.role ?? null;

return [{
  conversation_id,
  agent_id,
  last_message,
  last_role,
  message_count: transcript?.length ?? 0,
  processed_at: new Date().toISOString()
}];
